/**
 * @method 
 * @name uploadComplete 
 * @description Upload File complete
 */
scwin.uploadComplete = function () {
  // todo - 확인필요
  // fileUploadGDS.SortExpr = "+fileId";
  // fileUploadGDS.Sort();
  ds_attach.removeAll();
  const uploadAllData = udc_attachFile.getData();
  for (i = 0; i < uploadAllData.length; i++) {
    const rowData = uploadAllData[i];
    const insertIdx = ds_attach.insertRow();
    let insertData = {};
    insertData.attachFileId = "0001";
    if (insertIdx > 0) {
      let fltNxtSeq = $c.num.parseFloat($p, ds_attach.getCellData(insertIdx - 1, "attachFileId"), 0) + 1;
      let strNxtSeq = "000" + fltNxtSeq;
      insertData.attachFileId = strNxtSeq.slice(-4);
      uploadAllData[i].slipNo = strNxtSeq.slice(-4);
    }
    ;
    insertData.attachFileNm = rowData.ORIGIN_FILE_NM; //파일명
    insertData.attachFileDesc = rowData.ORIGIN_FILE_NM; //파일설명
    insertData.attachFileSiz = rowData.FILE_SIZE; //파일SIZE
    insertData.salesActivId = ed_odrNo.getValue(); //파일ID
    insertData.attachFilePath = rowData.FILE_STORED_PATH; //파일경로
    insertData.odrNo = ed_odrNo.getValue();
    ds_attach.setRowJSON(insertIdx, insertData, true);
  }
  ;
  const attachCnt = ds_attach.getRowCount();
  const uploadData = [];
  for (let i = 0; i < attachCnt; i++) {
    const rowData = ds_attach.getRowJSON(i);
    uploadData.push({
      'slipNo': rowData.attachFileId,
      'ORIGIN_FILE_NM': rowData.attachFileNm,
      'FILE_EXPLAIN': rowData.attachFileDesc,
      'FILE_SIZE': rowData.attachFileSiz,
      'status': uploadAllData[i].status
    });
  }
  ;
  udc_attachFile.setGridClear();
  udc_attachFile.setData(uploadData);
};

