/**
 * @method 
 * @name f_RegistNosellOrderPrimeCost 
 * @description 매입 생성
 */
scwin.f_RegistNosellOrderPrimeCost = async function () {
  // 매입거래처, 매입부서, 매입예정일자
  const validPchs = await $c.gus.cfValidate($p, [ed_bilgClntNo, ed_pchsClntNo, ed_pchsDeptCd, ica_spplyDt, ed_reqClntNo], null, true);
  if (!validPchs) return;

  // Data 변경 여부 조회
  if (ds_nosellPurchaseDTOList.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["매입 내역"]);
    return;
  }
  ;

  // 매입내역
  const validGrid = await $c.gus.cfValidate($p, [gr_nosellPurchaseDTOList], null, true);
  if (!validGrid) return;

  //구분이 CNTR-NO 일경우 Validation 체크
  const nosellCnt = ds_nosellPurchaseDTOList.getRowCount();
  for (i = 0; i < nosellCnt; i++) {
    const {
      pchsGoodsPatternCd,
      pchsCommNo
    } = ds_nosellPurchaseDTOList.getRowJSON(i);
    if (pchsGoodsPatternCd != "09" && pchsCommNo == "") {
      await $c.gus.cfAlertMsg($p, i + 1 + "번째 데이타의 품명(장비)코드를 입력하십시오.");
      return;
    }
    ;
  }
  ;

  // 차량번호 체크
  for (i = 0; i < nosellCnt; i++) {
    const {
      selpchItemCd,
      vehclNo
    } = ds_nosellPurchaseDTOList.getRowJSON(i);
    if (["0010", "0131"].includes(selpchItemCd) && vehclNo == "") {
      await $c.gus.cfAlertMsg($p, i + 1 + "번째 데이타의 차량번호를 입력하십시오.");
      return;
    }
    ;
  }
  ;

  //구분이 CNTR-NO 일경우 Validation 체크
  for (i = 0; i < nosellCnt; i++) {
    const {
      pchsGoodsPatternCd,
      cntrNo
    } = ds_nosellPurchaseDTOList.getRowJSON(i);
    if (pchsGoodsPatternCd == "01" && cntrNo == "") {
      await $c.gus.cfAlertMsg($p, i + 1 + "번째 데이타의 CNTR-NO를 입력하십시오.");
      return;
    }
    ;
  }
  ;
  for (let i = 0; i < nosellCnt; i++) {
    const {
      rsltsStdDt
    } = ds_nosellPurchaseDTOList.getRowJSON(i);
    const validDate = await $c.date.isDate($p, rsltsStdDt, false);
    if (!validDate) {
      await $c.gus.cfAlertMsg($p, i + 1 + "번째 데이타에서 실적일자는 'YYYYMMDD' 형식이어야 합니다.");
      return;
    }
    ;
  }
  ;

  // 저장하시겠습니까?
  const retConfrim = await $c.win.confirm($p, MSG_CM_CRM_001);
  if (!retConfrim) return;
  scwin.save = "REGIST";
  ds_purchaseEvidenceDTO.setCellData(0, "dcsnClsCd", "2"); // 확정구분코드(확인)
  sbm_saveNosellOrderPrimeCost.action = "/ds.fs.adjm.adjmbdcalc.RegistNosellOrderPrimeCostCMD.do";
  await scwin.submitExcute(sbm_saveNosellOrderPrimeCost);
};

/**
 * @method 
 * @name f_Delete 
 * @description 삭제
 */
scwin.f_Delete = async function () {
  if (ds_nosellPurchaseDTOList.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, "삭제할 목록이 존재하지 않습니다.");
    return;
  }
  ;

  // 확정구분이 미확인(1), 확인(2)이 아닌 상태는 삭제불가
  const focusIdx = ds_purchaseEvidenceDTO.getRowPosition();
  const {
    dcsnClsCd,
    dcsnClsNm
  } = ds_purchaseEvidenceDTO.getRowJSON(focusIdx);
  if (!["1", "2", ""].includes(dcsnClsCd) && ds_purchaseEvidenceDTO.getRowCount() != 0) {
    await $c.gus.cfAlertMsg($p, "확정구분이 미확인, 확인인 경우만 삭제가능합니다.");
    return;
  }
  ;
  const retConfirm = await $c.win.confirm($p, "삭제하시겠습니까?");
  if (!retConfirm) return;
  scwin.save = "DELETE";
  sbm_saveNosellOrderPrimeCost.action = "/ds.fs.adjm.adjmbdcalc.DeleteNosellOrderPrimeCostCMD.do";
  await scwin.submitExcute(sbm_saveNosellOrderPrimeCost);
};

