/**
 * @method 
 * @name f_saveFile 
 * @description 검색영역 Field Clear함.
 */
scwin.f_saveFile = async function () {
  const rowCnt = ds_attach.getRowCount();
  if (rowCnt == 0) {
    await $c.win.alert($p, "오더번호가 없습니다. 조회후 저장해 주세요");
    return false;
  }
  ;
  for (let i = 0; i < rowCnt; i++) {
    if (ds_attach.getCellData(i, "odrNo") == "") {
      await $c.win.alert($p, "오더번호가 없습니다. 조회후 저장해 주세요");
      return false;
    }
    ;
  }
  ;
  const retConfirm = await $c.win.confirm($p, "저장 하시겠습니까?");
  if (!retConfirm) return;

  // 저장전 rowStatus 세팅
  const attachData = ds_attach.getAllJSON();
  const updateData = udc_attachFile.getModifiedData();
  const updateMap = new Map(updateData.map(a => [a.slipNo, a]));
  attachData.forEach((attach, index) => {
    const match = updateMap.get(attach.attachFileId);
    if (match) {
      ds_attach.modifyRowStatus(index, match.rowStatus);
    }
    ;
  });
  await scwin.submitExcute(sbm_saveFile);
};

