/**
 * @method 
 * @name gr_nosellPurchaseDTOList_onafteredit 
 * @description 셀의 편집모드가 종료되어 포커스가 빠져나온 경우에 발생 (oneditend 이벤트 이후 발생)
 * @asis for=gr_nosellPurchaseDTOList event=OnExit(row,colid,olddata)
 */
scwin.gr_nosellPurchaseDTOList_onafteredit = async function (rowIndex, columnIndex, value) {
  const colId = this.getColumnID(columnIndex);

  // 그리드의 구분코드 선택시
  if (["vol", "pchsUpr", "pchsAmt", "vat"].includes(colId)) {
    // 물량, 매입단가, 매입금액, 매입부가세
    const rowData = ds_nosellPurchaseDTOList.getRowJSON(rowIndex);
    let vol = $c.num.parseFloat($p, rowData.vol, 0);
    let pchsUpr = $c.num.parseFloat($p, rowData.pchsUpr, 0);
    let pchsAmt = $c.num.parseFloat($p, rowData.pchsAmt, 0);
    let vat = $c.num.parseFloat($p, rowData.vat, 0);
    let totPchsAmt = 0,
      //매입합계
      pchsAmtTot = 0,
      pchsVatAmtTot = 0,
      totPchsAmtTot = 0;
    switch (colId) {
      case "vol":
        pchsAmt = vol * pchsUpr;
        vat = Math.round(pchsAmt / 10);
        break;
      case "pchsUpr":
        pchsAmt = vol * pchsUpr;
        vat = Math.round(pchsAmt / 10);
        break;
      case "pchsAmt":
        if (vol != 0) {
          pchsUpr = Math.floor(pchsAmt / vol);
        } else {
          pchsUpr = 0;
        }
        ;
        vat = Math.round(pchsAmt / 10);
        break;
    }
    ;
    totPchsAmt = pchsAmt + vat;
    ds_nosellPurchaseDTOList.setCellData(rowIndex, "vol", vol); //물량
    ds_nosellPurchaseDTOList.setCellData(rowIndex, "pchsUpr", pchsUpr); //매입단가 
    ds_nosellPurchaseDTOList.setCellData(rowIndex, "pchsAmt", pchsAmt); //매입금액
    ds_nosellPurchaseDTOList.setCellData(rowIndex, "vat", vat); //매입부가세
    ds_nosellPurchaseDTOList.setCellData(rowIndex, "totPchsAmt", totPchsAmt); //매입합계

    const rowCnt = ds_nosellPurchaseDTOList.getRowCount();
    for (i = 0; i < rowCnt; i++) {
      const {
        pchsAmt,
        vat,
        totPchsAmt
      } = ds_nosellPurchaseDTOList.getRowJSON(rowIndex);
      pchsAmtTot = pchsAmtTot + pchsAmt;
      pchsVatAmtTot = pchsVatAmtTot + vat;
      totPchsAmtTot = totPchsAmtTot + totPchsAmt;
    }
    ;
    ds_purchaseEvidenceDTO.setCellData(0, "spplyAmt", pchsAmtTot);
    ds_purchaseEvidenceDTO.setCellData(0, "vat", pchsVatAmtTot);
  }
  ;
  if (document.activeElement.getAttribute('data-inputtype') == 'textImage') return;
  switch (colId) {
    case "vehclNo":
      //차량번호
      if ($c.gus.cfIsNull($p, ed_pchsClntNo.getValue())) {
        await $c.win.alert($p, "매입거래처 입력 하세요.");
        return false;
      }
      ;
      scwin.f_Popup(4);
      break;
  }
  ;
};

/**
 * @method 
 * @name gr_nosellPurchaseDTOList_ontextimageclick 
 * @description inputType이 textImage인 경우 이미지가 클릭됐을 때 발생
 * @asis for=gr_nosellPurchaseDTOList event=OnPopup(row,colid,data)
 */
scwin.gr_nosellPurchaseDTOList_ontextimageclick = async function (rowIndex, columnIndex) {
  const colId = this.getColumnID(columnIndex);
  const rowData = ds_nosellPurchaseDTOList.getRowJSON(rowIndex);

  // 팝업창 띄우기
  switch (colId) {
    case "pchsCommNo":
      const popMap = {
        "01": 1,
        "02": 1,
        "03": 2,
        "04": 3
      };
      const popVal = popMap[rowData.pchsGoodsPatternCd];
      if ($c.util.isEmpty($p, popVal)) return;
      scwin.f_Popup(popVal);
      break;
    case "vehclNo":
      if (ed_pchsClntNo.getValue() == "") {
        await $c.win.alert($p, "매입거래처를 입력하세요");
        ed_pchsClntNo.focus();
        return;
      }
      ;
      scwin.f_Popup(4);
      break;
    case "reqClntNm":
      scwin.f_Popup(5);
      break;
    default:
      return;
  }
  ;
};

